// // This module selects between two input signals, A and B, based on the inverted value of the select signal, SEL. When SEL is high (1), the output Y will be equal to B; when SEL is low (0), Y will be equal to A.
module top_module(
    A,
    B,
    SEL,
    Y
);// Module ports
    input  A;
    input  B;
    input  SEL;
    output Y;

    // Local signals
    wire not_SEL;

    // Invert SEL signal
    not not_SEL_inst (
        not_SEL,
        SEL
    );

    // Multiplexer
    assign Y = (SEL & A) | (not_SEL & B);

endmodule
